//! Regression tests using real wire captures from production dongle trace logs.
//!
//! Every packet in this file was captured from a live Wyze Sense dongle and
//! the expected values were independently verified against the Python reference
//! implementation (wyzesense.py) output.
//!
//! Capture files under tests/captures/ are generated by:
//!   python3 tools/extract_packets.py trace.log > tests/captures/session.jsonl

use wyzesense2mqtt_rs::protocol::packet::{Packet, commands, PacketPayload};
use wyzesense2mqtt_rs::protocol::telemetry::{DongleEvent, SensorType};
use wyzesense2mqtt_rs::protocol::sensor::{WyzeSensor, SensorManager};
use serde::Deserialize;
use std::path::Path;

