#[test]
fn test_real_capture_climate_event_21_46c() {
    // Source: trace_cli.log line 10 → "STATE EVENT: MAC=77C68193, Data=Climate { temperature: 21.46, humidity: 48 }"
    // This is the PAYLOAD of a 0x5319 packet (after packet header is stripped)
    let payload = vec![
        0x00, 0x00, 0x01, 0x9E, 0x68, 0xB1, 0x59, 0xEA, // Timestamp
        0xE8, // EVENT_TYPE_CLIMATE
        0x37, 0x37, 0x43, 0x36, 0x38, 0x31, 0x39, 0x33, // MAC: "77C68193"
        0x07, // SensorType: Climate (0x07)
        // Remaining 10 bytes (Climate data format: >BBBBBBBBBB):
        0x15, // [0]: data_type
        0x5F, // [1]: battery = 95%
        0x00, // [2]: unknown
        0x03, // [3]: unknown
        0x15, // [4]: temp_hi = 21
        0x2E, // [5]: temp_lo = 46 → 21.46°C
        0x30, // [6]: humidity = 48%
        0x11, // [7]: unknown
        0x36, // [8]: seq
        0x26, // [9]: RSSI = 38 → -38 dBm
    ];

    let event = DongleEvent::parse_alarm1(&payload).unwrap();
    assert_eq!(event.mac, "77C68193");
    assert_eq!(event.sensor_type, SensorType::ClimateV2);
    
    let mut sensor = WyzeSensor::new(
        event.mac.clone(),
        event.sensor_type,
        "Climate Sensor".to_string(),
    );
    sensor.update_from_event(&event).unwrap();

    // raw 0x5F=95 → 2.97V on 3V coin cell curve → ~87% capacity
    assert_eq!(sensor.battery_pct, Some(87));
    assert_eq!(sensor.rssi_dbm, -38);
    let state = sensor.get_state_payload();
    assert_eq!(state["temperature"], "21.46");
    assert_eq!(state["humidity"], 48);
}

