// =============================================================================
// MULTI-PACKET STREAM — Parsing multiple packets from a single buffer
// =============================================================================

#[test]
fn test_real_capture_two_packets_concatenated() {
    // Simulates what happens when a large HID frame contains multiple packets.
    // Packet 1: Inquiry Response (8 bytes)
    // Packet 2: Sensor list ACK (7 bytes)
    let stream = [
        // Packet 1: Inquiry Response
        0x55, 0xAA, 0x43, 0x04, 0x28, 0x01, 0x01, 0x6F,
        // Packet 2: ACK for 0x5330
        0x55, 0xAA, 0x53, 0x30, 0xFF, 0x02, 0x81,
    ];

    // Parse first packet
    let (pkt1, consumed1) = Packet::parse(&stream).unwrap();
    assert_eq!(consumed1, 8);
    assert_eq!(pkt1.cmd(), commands::CMD_INQUIRY_RESPONSE);

    // Parse second packet from remaining bytes
    let (pkt2, consumed2) = Packet::parse(&stream[consumed1..]).unwrap();
    assert_eq!(consumed2, 7);
    assert_eq!(pkt2.cmd(), commands::CMD_ASYNC_ACK);
    assert_eq!(pkt2.payload, wyzesense2mqtt_rs::protocol::packet::PacketPayload::Ack(commands::CMD_GET_SENSOR_LIST));
}

#[test]
fn test_parse_fails_on_truncated_packet() {
    // Only first 5 bytes of an 8-byte packet — should fail gracefully
    let truncated = [0x55, 0xAA, 0x43, 0x04, 0x28];

    let result = Packet::parse(&truncated);
    assert!(result.is_err(), "Should fail to parse truncated packet");
}

#[test]
fn test_parse_fails_on_bad_checksum() {
    // Valid structure but wrong checksum (last 2 bytes mangled)
    let bad = [0x55, 0xAA, 0x43, 0x04, 0x28, 0x01, 0xFF, 0xFF];

    let result = Packet::parse(&bad);
    assert!(result.is_err(), "Should fail on bad checksum");
}

#[test]
fn test_real_capture_round_trip_inquiry() {
    // Write inquiry → serialize → parse back → compare
    let original = Packet::new_sync((commands::CMD_INQUIRY & 0xFF) as u8, vec![]);
    let serialized = original.to_bytes();

    // Verify against known wire bytes
    assert_eq!(serialized, vec![0xAA, 0x55, 0x43, 0x03, 0x27, 0x01, 0x6C]);

    // Round-trip parse
    let (parsed, _) = Packet::parse(&serialized).unwrap();
    assert_eq!(parsed.cmd(), original.cmd());
    assert_eq!(parsed.payload_bytes(), original.payload_bytes());
}

#[test]
fn test_real_capture_round_trip_ack() {
    // Construct ACK for 0x5319 → serialize → verify wire format
    let ack = Packet::new_ack(commands::CMD_ALARM1);
    let bytes = ack.to_bytes();

    // Parse back
    let (parsed, consumed) = Packet::parse(&bytes).unwrap();
    assert_eq!(consumed, 7);
    assert_eq!(parsed.payload, wyzesense2mqtt_rs::protocol::packet::PacketPayload::Ack(commands::CMD_ALARM1));
}

// =============================================================================
// CAPTURE FILE LOADING — Parse packets from extracted trace log JSONL files
// =============================================================================

/// A captured I/O record loaded from a JSONL file.
#[derive(Debug, Deserialize)]
#[allow(dead_code)]
struct CaptureRecord {
    #[allow(dead_code)]
    ts_ms: u64,
    dir: String,
    proto_hex: String,
    proto_len: usize,
    #[serde(default)]
    raw_hex: Option<String>,
    #[serde(default)]
    raw_len: Option<usize>,
}

fn hex_to_bytes(hex: &str) -> Vec<u8> {
    (0..hex.len())
        .step_by(2)
        .filter_map(|i| {
            if i + 2 <= hex.len() {
                u8::from_str_radix(&hex[i..i + 2], 16).ok()
            } else {
                None
            }
        })
        .collect()
}

fn load_capture_file(path: &Path) -> Vec<CaptureRecord> {
    let content = std::fs::read_to_string(path)
        .unwrap_or_else(|e| panic!("Failed to load capture file {:?}: {}", path, e));
    content
        .lines()
        .filter(|line| !line.trim().is_empty())
        .map(|line| serde_json::from_str(line)
            .unwrap_or_else(|e| panic!("Failed to parse JSONL line: {} -- {}", e, line)))
        .collect()
}

#[test]
fn test_all_captures_in_directory_parseable() {
    let captures_dir = Path::new("tests/captures");
    if !captures_dir.exists() {
        eprintln!("Skipping capture directory tests: {:?} not found", captures_dir);
        return;
    }

    let dir_entries = std::fs::read_dir(captures_dir)
        .unwrap_or_else(|e| panic!("Failed to read captures directory: {}", e));

    let mut tested_files = 0;
    let mut total_records_parsed = 0;
    let mut total_write_roundtrips = 0;

    for entry in dir_entries {
        let entry = entry.unwrap();
        let path = entry.path();
        if path.is_file() && path.extension().map_or(false, |ext| ext == "jsonl") {
            let filename = path.file_name().unwrap().to_string_lossy().into_owned();
            println!("Testing capture file: {}", filename);

            let records = load_capture_file(&path);
            assert!(!records.is_empty(), "Capture file {} is empty", filename);

            let mut total_parsed = 0;
            let mut total_fragments = 0;
            let mut failures = Vec::new();

            // Setup a test-local SensorManager for visual state checking
            let test_config_path = format!("target/test_sensors_{}.yaml", filename.replace(".", "_"));
            let test_state_path = format!("target/test_state_{}.yaml", filename.replace(".", "_"));
            
            let _ = std::fs::remove_file(&test_config_path);
            let _ = std::fs::remove_file(&test_state_path);

            let mut manager = SensorManager::new(
                test_config_path.clone(),
                test_state_path.clone(),
            );

            for (idx, rec) in records.iter().enumerate() {
                // 1. Verify basic length match
                assert_eq!(rec.proto_hex.len() / 2, rec.proto_len,
                    "Record {}: proto_hex length mismatch in {}", idx, filename);

                // 2. Parse protocol bytes
                let bytes = hex_to_bytes(&rec.proto_hex);
                if bytes.is_empty() {
                    continue;
                }

                let mut offset = 0;
                let mut parsed_in_rec = 0;
                let mut first_err = None;

                while offset < bytes.len() {
                    match Packet::parse(&bytes[offset..]) {
                        Ok((pkt, consumed)) => {
                            offset += consumed;
                            parsed_in_rec += 1;
                            total_parsed += 1;
                            total_records_parsed += 1;

                            // If read from dongle, route events to the SensorManager
                            if rec.dir == "R" {
                                let mut event_opt = None;
                                match pkt.cmd() {
                                    commands::CMD_ALARM1 => {
                                        if let PacketPayload::Bytes(payload) = pkt.payload {
                                            if let Ok(evt) = DongleEvent::parse_alarm1(&payload) {
                                                event_opt = Some(evt);
                                            }
                                        }
                                    }
                                    commands::CMD_ALARM2 => {
                                        if let PacketPayload::Bytes(payload) = pkt.payload {
                                            if let Ok(evt) = DongleEvent::parse_alarm2(&payload) {
                                                event_opt = Some(evt);
                                            }
                                        }
                                    }
                                    commands::CMD_SENSOR_SCAN => {
                                        if let PacketPayload::Bytes(payload) = pkt.payload {
                                            if let Ok(evt) = DongleEvent::parse_scan(&payload) {
                                                event_opt = Some(evt);
                                            }
                                        }
                                    }
                                    _ => {}
                                }

                                if let Some(evt) = event_opt {
                                    if manager.dispatch_event(&evt) {
                                        if let Some(sensor) = manager.get_sensors().get(&evt.mac) {
                                            let payload = sensor.get_state_payload();
                                            println!("  Sensor MAC: {} | State: {}", evt.mac, serde_json::to_string(&payload).unwrap());
                                        }
                                    }
                                }
                            }
                        }
                        Err(e) => {
                            if parsed_in_rec == 0 {
                                first_err = Some(format!("offset {}: {}", offset, e));
                            }
                            break; // remaining bytes may be stale HID data
                        }
                    }
                }

                if parsed_in_rec == 0 {
                    if let Some(e) = first_err {
                        // Records that start with stale HID buffer data (no valid magic) are fragments
                        let magic = if bytes.len() >= 2 { (bytes[0] as u16) << 8 | bytes[1] as u16 } else { 0 };
                        if magic == 0x55AA || magic == 0xAA55 {
                            failures.push((idx, rec.dir.clone(), e));
                        } else {
                            total_fragments += 1;
                        }
                    }
                }

                // 3. If raw_hex is present, verify extract_hid_frame extracts proto_hex exactly!
                if let (Some(raw_hex), Some(raw_len)) = (&rec.raw_hex, rec.raw_len) {
                    let raw_bytes = hex_to_bytes(raw_hex);
                    assert_eq!(raw_bytes.len(), raw_len,
                        "Record {}: raw_hex length mismatch in {}", idx, filename);

                    let mut extracted_buf = vec![0u8; raw_bytes.len() * 2];
                    let extracted_len = wyzesense2mqtt_rs::transport::hidraw::extract_hid_frame(&raw_bytes, &mut extracted_buf);
                    
                    let expected_proto = hex_to_bytes(&rec.proto_hex);
                    assert_eq!(extracted_len, rec.proto_len,
                        "Record {}: extracted proto length mismatch in {}", idx, filename);
                    assert_eq!(&extracted_buf[..extracted_len], &expected_proto,
                        "Record {}: extracted proto bytes mismatch in {}", idx, filename);
                }

                // 4. If it's a write packet, verify round-trip serialization works perfectly!
                if rec.dir == "W" {
                    let bytes = hex_to_bytes(&rec.proto_hex);
                    if let Ok((pkt, consumed)) = Packet::parse(&bytes) {
                        let reserialized = pkt.to_bytes();
                        assert_eq!(reserialized, bytes[..consumed],
                            "Record {}: round-trip serialization mismatch for write packet in {}", idx, filename);
                        total_write_roundtrips += 1;
                    }
                }
            }

            // Visual Sensor State Printer
            println!("\n=======================================================================");
            println!("Consolidated Sensor States for Capture File: {}", filename);
            println!("=======================================================================");
            let sensors = manager.get_sensors();
            if sensors.is_empty() {
                println!("  No sensors discovered in this capture session.");
            } else {
                for (mac, sensor) in sensors {
                    let payload = sensor.get_state_payload();
                    println!("  Sensor MAC: {} | State: {}", mac, serde_json::to_string(&payload).unwrap());
                }
            }
            println!("=======================================================================\n");

            // Clean up temporary files
            let _ = std::fs::remove_file(&test_config_path);
            let _ = std::fs::remove_file(&test_state_path);

            println!("  Success: {} records, {} packets parsed, {} fragments skipped, {} failures",
                records.len(), total_parsed, total_fragments, failures.len());

            for (idx, dir, err) in &failures {
                eprintln!("  FAIL record #{} (dir={}): {}", idx, dir, err);
            }

            assert!(failures.is_empty(),
                "Some records with valid magic failed to parse in {}: {:?}", filename, failures);

            tested_files += 1;
        }
    }

    println!("Capture test run complete. Tested {} files, parsed {} total packets, validated {} write roundtrips.",
        tested_files, total_records_parsed, total_write_roundtrips);
    
    assert!(tested_files > 0, "No capture files (.jsonl) found under tests/captures/");
}


